"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import axios from "axios";
import { AnimatedSection } from "@/components/ui";
import { Users, Calendar, Clock, User, Building, RefreshCw, Bell } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/context/AuthContext";
import Link from "next/link";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

interface Order {
  id: number;
  customer_name: string;
  email: string;
  date: string;
  time: string;
  people: number;
  section: string;
  duration: string;
  table_id: number;
}

export default function OrdersPage() {
  const { role } = useAuth();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const prevCountRef = useRef(0);

  const fetchOrders = useCallback(async () => {
    try {
      const res = await axios.get(`${API_URL}/restaurant/orders`);
      const newOrders: Order[] = res.data;

      if (prevCountRef.current > 0 && newOrders.length > prevCountRef.current) {
        const latest = newOrders[0];
        toast.success(
          `New Reservation Received – Table for ${latest.people} booked.`,
          {
            description: `${latest.customer_name} • ${latest.date} • ${latest.duration}`,
            icon: <Bell className="text-[#C9A96E]" size={18} />,
            duration: 5000,
          }
        );
      }

      prevCountRef.current = newOrders.length;
      setOrders(newOrders);
    } catch {
      // silently fail on poll errors
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (role === "admin") {
      fetchOrders();
      const interval = setInterval(fetchOrders, 5000);
      return () => clearInterval(interval);
    }
  }, [fetchOrders, role]);

  const sectionColor = (section: string): React.CSSProperties =>
    section === "AC"
      ? { backgroundColor: 'rgba(59, 130, 246, 0.1)', color: 'rgb(96, 165, 250)', border: '1px solid rgba(59, 130, 246, 0.2)', padding: '4px 12px', borderRadius: '6px' }
      : { backgroundColor: 'rgba(249, 115, 22, 0.1)', color: 'rgb(251, 146, 60)', border: '1px solid rgba(249, 115, 22, 0.2)', padding: '4px 12px', borderRadius: '6px' };

  const durationColor = (duration: string): React.CSSProperties => {
    const base: React.CSSProperties = { padding: '4px 12px', borderRadius: '6px' };
    switch (duration) {
      case "breakfast": return { ...base, backgroundColor: 'rgba(245, 158, 11, 0.1)', color: 'rgb(251, 191, 36)' };
      case "lunch": return { ...base, backgroundColor: 'rgba(16, 185, 129, 0.1)', color: 'rgb(52, 211, 153)' };
      case "dinner": return { ...base, backgroundColor: 'rgba(139, 92, 246, 0.1)', color: 'rgb(167, 139, 250)' };
      default: return { ...base, backgroundColor: 'rgba(255, 255, 255, 0.05)', color: 'rgba(255, 255, 255, 0.5)' };
    }
  };

  return (
    <>
      {/* Hero */}
      <section className="relative w-full h-[45vh] flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0" style={{ background: 'linear-gradient(135deg, #0D0D0D, #1A1A1A, #0D0D0D)' }} />
        <div className="absolute inset-0 opacity-20">
          <div className="absolute top-20 left-20 w-72 h-72 rounded-full blur-3xl" style={{ backgroundColor: 'rgba(201, 169, 110, 0.1)' }} />
          <div className="absolute bottom-20 right-20 w-96 h-96 rounded-full blur-3xl" style={{ backgroundColor: 'rgba(201, 169, 110, 0.05)' }} />
        </div>
        <div className="relative text-center px-6">
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="text-[#C9A96E] text-xs tracking-[0.4em] uppercase mb-5"
          >
            Administration
          </motion.p>
          <motion.h1
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4, duration: 0.8 }}
            className="font-serif text-5xl md:text-7xl text-[#F5F0EB]"
          >
            Orders Dashboard
          </motion.h1>
        </div>
      </section>

      {/* If not admin, gate the dashboard */}
      {role !== "admin" ? (
        <section className="w-full py-24" style={{ backgroundColor: "#0D0D0D" }}>
          <div className="max-w-3xl mx-auto px-6 text-center">
            <h2 className="font-serif text-3xl text-[#F5F0EB] mb-4">Admin Access Required</h2>
            <p className="text-sm text-[#F5F0EB]/60 mb-8">
              The Orders dashboard is restricted. Please log in as an admin to view live reservations.
            </p>
            <Link href="/login" className="btn-gold">
              Go to Login
            </Link>
          </div>
        </section>
      ) : (
      /* Dashboard */
      <section className="section-wrapper" style={{ backgroundColor: '#0D0D0D' }}>
        <div className="container-x">
          {/* Header bar */}
          <div className="flex flex-col sm:flex-row gap-6 items-start sm:items-center justify-between mb-10">
            <div>
              <h2 className="font-serif text-3xl text-[#F5F0EB] mb-2">Reservations</h2>
              <p className="text-sm text-[#F5F0EB]/40">
                {orders.length} total • Auto-refreshing every 5s
              </p>
            </div>
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={fetchOrders}
              className="flex items-center gap-3 px-6 py-3 text-[#C9A96E] text-sm rounded-lg hover:bg-[#C9A96E]/10 transition-colors"
              style={{ border: '1px solid rgba(201, 169, 110, 0.3)' }}
            >
              <RefreshCw size={15} />
              Refresh
            </motion.button>
          </div>

          {/* Loading */}
          {loading && (
            <div className="flex items-center justify-center py-24">
              <div className="w-12 h-12 rounded-full animate-spin" style={{ border: '2px solid rgba(201, 169, 110, 0.2)', borderTopColor: '#C9A96E' }} />
            </div>
          )}

          {/* Empty */}
          {!loading && orders.length === 0 && (
            <div className="text-center py-24 rounded-xl" style={{ background: 'rgba(26, 26, 26, 0.6)', backdropFilter: 'blur(20px)', border: '1px solid rgba(201, 169, 110, 0.15)' }}>
              <Calendar className="text-[#C9A96E]/30 mx-auto mb-6" size={56} />
              <h3 className="font-serif text-2xl text-[#F5F0EB] mb-3">No Reservations Yet</h3>
              <p className="text-sm text-[#F5F0EB]/40">New bookings will appear here in real time.</p>
            </div>
          )}

          {/* Order cards */}
          <AnimatePresence>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 lg:gap-10">
              {orders.map((order, i) => (
                <motion.div
                  key={order.id}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.9 }}
                  transition={{ delay: i * 0.05 }}
                  whileHover={{ y: -3, boxShadow: "0 18px 50px rgba(201, 169, 110, 0.06)" }}
                  className="surface rounded-xl p-8 cursor-default"
                >
                  {/* Top */}
                  <div className="flex items-start justify-between mb-6">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-full flex items-center justify-center" style={{ backgroundColor: 'rgba(201, 169, 110, 0.1)' }}>
                        <User className="text-[#C9A96E]" size={20} />
                      </div>
                      <div>
                        <p className="text-[#F5F0EB] font-medium mb-1">{order.customer_name}</p>
                        <p className="text-[#F5F0EB]/30 text-xs">{order.email}</p>
                      </div>
                    </div>
                    <span className="text-xs text-[#F5F0EB]/20">#{order.id}</span>
                  </div>

                  {/* Details grid */}
                  <div className="grid grid-cols-2 gap-4 mb-6">
                    <div className="flex items-center gap-3 text-[#F5F0EB]/50 text-sm">
                      <Calendar size={14} className="text-[#C9A96E]/60" />
                      {order.date}
                    </div>
                    <div className="flex items-center gap-3 text-[#F5F0EB]/50 text-sm">
                      <Clock size={14} className="text-[#C9A96E]/60" />
                      {order.time}
                    </div>
                    <div className="flex items-center gap-3 text-[#F5F0EB]/50 text-sm">
                      <Users size={14} className="text-[#C9A96E]/60" />
                      {order.people} Guest{order.people !== 1 ? "s" : ""}
                    </div>
                    <div className="flex items-center gap-3 text-[#F5F0EB]/50 text-sm">
                      <Building size={14} className="text-[#C9A96E]/60" />
                      Table {order.table_id}
                    </div>
                  </div>

                  {/* Tags */}
                  <div className="flex gap-3">
                    <span className="text-[10px] tracking-wider uppercase" style={sectionColor(order.section)}>
                      {order.section}
                    </span>
                    <span className="text-[10px] tracking-wider uppercase" style={durationColor(order.duration)}>
                      {order.duration}
                    </span>
                  </div>
                </motion.div>
              ))}
            </div>
          </AnimatePresence>
        </div>
      </section>
      )}
    </>
  );
}
